import datetime

class RequestLogger:
    def __init__(self):
        self.logs = []

    def log(self, method, path, status, duration_ms):
        self.logs.append({
            "timestamp": datetime.datetime.utcnow().isoformat(),
            "method": method,
            "path": path,
            "status": status,
            "duration_ms": duration_ms,
        })

    def get_recent(self, n=100):
        return self.logs[-n:]

